// Ottieni la data di oggi
const today = new Date().toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric' });

// Intestazione principale
let discordMessage = `# 🎬 PROGRAMMAZIONE BARI | ${today}\n\n`;

const items = $input.all();

items.forEach((item) => {
    const movie = item.json;

    // 1. Titolo
    const displayTitle = movie.original_title ? movie.original_title : (movie.title || "Titolo Sconosciuto");

    // 1b. Genere: spazio + parentesi (testo normale)
    const genreSuffix = movie.genres ? ` (${movie.genres})` : "";

    // 2. Regista e Cast
    const director = movie.director || "";

    let shortCast = "";
    if (movie.cast) {
        const castArray = Array.isArray(movie.cast) ? movie.cast : movie.cast.split(',');
        shortCast = castArray.map(c => c.trim()).slice(0, 3).join(', ');
    }

    // Costruisce la riga credits aggiungendo '*' all'inizio e alla fine per il CORSIVO
    let creditsLine = "";
    let content = "";

    if (director && shortCast) {
        content = `${director} ~ ${shortCast}`;
    } else if (director) {
        content = `${director}`;
    } else if (shortCast) {
        content = `${shortCast}`;
    }

    // Se c'è contenuto, aggiunge l'icona, va a capo e applica il corsivo (*)
    if (content) {
        creditsLine = `\n*🎭 ${content}*`;
    }

    // 3. Cinema e Orari
    let cinemasText = "";
    if (movie.cinemas && Array.isArray(movie.cinemas)) {
        movie.cinemas.forEach(cinema => {
            const times = Array.isArray(cinema.times) ? cinema.times.join(", ") : cinema.times;
            cinemasText += `\n📍 **${cinema.name}:** ${times}`;
        });
    }

    // Assemblaggio:
    // ABBIAMO RIMOSSO "###" -> Altrimenti Discord fa tutta la riga in grassetto.
    // Ora: Emoji + Titolo in grassetto + Genere normale
    discordMessage += `🎞️ **${displayTitle}**${genreSuffix}`;
    discordMessage += creditsLine; 
    discordMessage += cinemasText;

    discordMessage += `\n\n`;
});

// Pulizia finale
discordMessage = discordMessage.trimEnd();

return[{
    json: {
        discord_message: discordMessage
    }
}];

// Prendiamo tutti gli elementi in input e li trasformiamo in un unico array JSON
const allMovies = $input.all().map(item => item.json);

// Restituiamo un singolo elemento che contiene l'array convertito in formato Testo (Stringa JSON)
return [{
    json: {
        fileContent: JSON.stringify(allMovies, null, 2)
    }
}];
